import React, { useState } from 'react';

const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);
    // TO DO: Implement login logic here
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <form onSubmit={handleSubmit} className="bg-white p-4 rounded shadow">
        <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Username" className="block w-full p-2 mb-2"/>
        <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password" className="block w-full p-2 mb-2"/>
        <button type="submit" className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded">Login</button>
        {loading ? <div className="text-center text-white">Loading...</div> : null}
        {success ? <div className="text-center text-white">Logged in successfully!</div> : null}
      </form>
    </div>
  );
};

export default App;
